  1	import * as React from 'react';
  2	import { Stack, StackItem, Title } from '@patternfly/react-core';
  3	import { FormikErrors, useField } from 'formik';
  4	import { Trans, useTranslation } from 'react-i18next';
  5	import {
  6	  PipelineTask,
  7	  PipelineTaskParam,
  8	  TektonResource,
  9	  TektonWorkspace,
 10	  TektonParam,
 11	  PipelineTaskResource,
 12	  ResourceTarget,
 13	  TektonResourceGroup,
 14	  SelectedBuilderTask,
 15	} from '../../../types';
 16	import TaskSidebarHeader from './TaskSidebarHeader';
 17	import TaskSidebarName from './TaskSidebarName';
 18	import TaskSidebarParam from './TaskSidebarParam';
 19	import TaskSidebarResource from './TaskSidebarResource';
 20	import TaskSidebarWhenExpression from './TaskSidebarWhenExpression';
 21	import TaskSidebarWorkspace from './TaskSidebarWorkspace';
 22	
 23	import './TaskSidebar.scss';
 24	import { TaskType, UpdateOperationRenameTaskData } from '../types';
 25	import { getTaskParameters, getTaskResources } from '../utils';
 26	import { CloseButton } from '@patternfly/react-component-groups';
 27	
 28	type TaskSidebarProps = {
 29	  errorMap: FormikErrors<PipelineTask>[];
 30	  onRemoveTask: (taskName: string) => void;
 31	  onRenameTask: (data: UpdateOperationRenameTaskData) => void;
 32	  resourceList: TektonResource[];
 33	  workspaceList: TektonWorkspace[];
 34	  selectedData: SelectedBuilderTask;
 35	  onClose: () => void;
 36	};
 37	
 38	/** Protect against -1 index for Formik 'name' use-cases */
 39	function safeIndex<T>(list: T[], comparatorFunc: (v: T) => boolean): number {
 40	  const idx = list.findIndex(comparatorFunc);
 41	  return idx === -1 ? list.length : idx;
 42	}
 43	
 44	const TaskSidebar: React.FC<TaskSidebarProps> = (props) => {
 45	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 46	  const {
 47	    onRemoveTask,
 48	    onRenameTask,
 49	    resourceList,
 50	    workspaceList,
 51	    selectedData,
 52	    onClose,
 53	  } = props;
 54	  const { isFinallyTask, taskIndex, resource: taskResource } = selectedData;
 55	  const taskType: TaskType = isFinallyTask ? 'finallyTasks' : 'tasks';
 56	  const formikTaskReference = `formData.${taskType}.${taskIndex}`;
 57	  const [{ value: thisTask }] = useField<PipelineTask>(formikTaskReference);
 58	
 59	  const params: TektonParam[] = getTaskParameters(taskResource) || [];
 60	  const resources: TektonResourceGroup<TektonResource> =
 61	    getTaskResources(taskResource);
 62	  const inputResources: TektonResource[] = resources.inputs || [];
 63	  const outputResources: TektonResource[] = resources.outputs || [];
 64	  const workspaces: TektonWorkspace[] = taskResource.spec.workspaces || [];
 65	
 66	  const renderResource =
 67	    (type: ResourceTarget) => (resource: TektonResource) => {
 68	      const taskResources: PipelineTaskResource[] =
 69	        thisTask.resources?.[type] || [];
 70	      const resourceIdx = safeIndex(
 71	        taskResources,
 72	        (thisParam) => thisParam.name === resource.name,
 73	      );
 74	      return (
 75	        <div key={resource.name} className="odc-task-sidebar__resource">
 76	          <TaskSidebarResource
 77	            availableResources={resourceList}
 78	            hasResource={!!taskResources[resourceIdx]}
 79	            name={`${formikTaskReference}.resources.${type}.${resourceIdx}`}
 80	            resource={resource}
 81	          />
 82	        </div>
 83	      );
 84	    };
 85	
 86	  return (
 87	    <Stack className="opp-task-sidebar">
 88	      <StackItem className="co-sidebar-dismiss  clearfix">
 89	        <CloseButton
 90	          onClick={onClose}
 91	          dataTestID="sidebar-close-button"
 92	          // ClassName="co-close-button--float-right co-sidebar-dismiss__close-button"
 93	        />
 94	      </StackItem>
 95	      <StackItem className="opp-task-sidebar__header">
 96	        <TaskSidebarHeader
 97	          taskResource={taskResource}
 98	          removeThisTask={() => onRemoveTask(thisTask.name)}
 99	        />
100	      </StackItem>
101	      <StackItem className="opp-task-sidebar__content pf-v6-c-form">
102	        <TaskSidebarName
103	          name={`${formikTaskReference}.name`}
104	          taskName={taskResource.metadata.name}
105	          // We need to do this through an update call because runAfters are tied to the name and we need to fix those
106	          // with this change to maintain a healthy and stable graph
107	          onChange={(newName) =>
108	            onRenameTask({ preChangePipelineTask: thisTask, newName })
109	          }
110	        />
111	
112	        {params.length > 0 && (
113	          <div>
114	            <Title headingLevel="h2">{t('Parameters')}</Title>
115	            <p className="co-help-text opp-task-sidebar__paragraph">
116	              <Trans ns="plugin__pipelines-console-plugin">
117	                Use this format when you reference variables in this form:{' '}
118	                <code className="co-code">$(</code>
119	              </Trans>
120	            </p>
121	            {params.map((param) => {
122	              const taskParams: PipelineTaskParam[] = thisTask.params || [];
123	              const paramIdx = safeIndex(
124	                taskParams,
125	                (thisParam) => thisParam.name === param.name,
126	              );
127	              return (
128	                <div key={param.name} className="opp-task-sidebar__param">
129	                  <TaskSidebarParam
130	                    hasParam={!!taskParams[paramIdx]}
131	                    name={`${formikTaskReference}.params.${paramIdx}`}
132	                    resourceParam={param}
133	                    selectedData={selectedData}
134	                  />
135	                </div>
136	              );
137	            })}
138	          </div>
139	        )}
140	        {workspaces.length > 0 && (
141	          <div>
142	            <h2>{t('Workspaces')}</h2>
143	            {workspaces.map((workspace) => {
144	              const taskWorkspaces: TektonWorkspace[] =
145	                thisTask.workspaces || [];
146	              const workspaceIdx = safeIndex(
147	                taskWorkspaces,
148	                (thisWorkspace) => thisWorkspace.name === workspace.name,
149	              );
150	              return (
151	                <div
152	                  key={workspace.name}
153	                  className="opp-task-sidebar__workspace"
154	                >
155	                  <TaskSidebarWorkspace
156	                    availableWorkspaces={workspaceList}
157	                    hasWorkspace={!!taskWorkspaces[workspaceIdx]}
158	                    name={`${formikTaskReference}.workspaces.${workspaceIdx}`}
159	                    resourceWorkspace={workspace}
160	                  />
161	                </div>
162	              );
163	            })}
164	          </div>
165	        )}
166	
167	        {inputResources.length > 0 && (
168	          <div>
169	            <h2>{t('Input resources')}</h2>
170	            {inputResources.map(renderResource('inputs'))}
171	          </div>
172	        )}
173	        {outputResources.length > 0 && (
174	          <div>
175	            <h2>{t('Output resources')}</h2>
176	            {outputResources.map(renderResource('outputs'))}
177	          </div>
178	        )}
179	        <div className="opp-task-sidebar__when-expressions">
180	          <TaskSidebarWhenExpression
181	            hasParam={false}
182	            name={`${formikTaskReference}.when`}
183	            selectedData={selectedData}
184	          />
185	        </div>
186	      </StackItem>
187	    </Stack>
188	  );
189	};
190	
191	export default TaskSidebar;

